SELECT COUNT(*)
FROM comment
WHERE deleted = 0 AND article_id = #{query.articleId}

SELECT c.id, c.parent_id, c.content, c.floor, c.like_count, c.reply_count, c.status as review_status, c.top, c.top_order, c.mention_user_ids, c.create_time, c.update_time, c.article_id, c.user_id, c.deleted, a.title as article_title, u.nickname, u.avatar, u.gender, u.status as user_status FROM comment c LEFT JOIN user u ON c.user_id = u.id LEFT JOIN article a ON c.article_id = a.id WHERE c.deleted = 0
AND c.content LIKE CONCAT('%', #{query.keyword}, '%')
AND c.article_id = #{query.articleId}
AND c.user_id = #{query.userId}
AND c.status = #{query.status}
ORDER BY c.create_time DESC LIMIT #{query.offset}, #{query.pageSize}

SELECT COUNT(*)
FROM comment c
WHERE c.deleted = 0

    AND c.content LIKE CONCAT('%', #{query.keyword}, '%')


    AND c.article_id = #{query.articleId}


    AND c.user_id = #{query.userId}


    AND c.status = #{query.status}

SELECT COUNT(*)
FROM comment
WHERE deleted = 0 AND user_id = #{userId}

SELECT COUNT(*)
FROM comment
WHERE deleted = 0 AND parent_id = #{parentId}

SELECT MAX(comment_version) as max_version
FROM comment
WHERE deleted = 0 AND article_id = #{articleId}
